### Swift Generic Constraints

Generic constraints specify requirements for type parameters, enabling you to write code that works only with types that meet certain criteria.

**Constraint Syntax:**

```swift
// Protocol constraint
func someFunction<T: SomeProtocol>(value: T) { }

// Equatable constraint (can use ==)
func findIndex<T: Equatable>(of: T, in: [T]) -> Int? { }

// Class constraint
func process<T: SomeClass>(object: T) { }

// Where clause (more complex constraints)
func process<T>(value: T) where T: Equatable, T: Hashable { }
```

**Common Constraints:**

| Constraint | Syntax | Example |
|------------|--------|---------|
| Protocol | `T: Equatable` | Types that can be compared |
| Class | `T: NSObject` | Subclasses of a class |
| Same type | `T == U` | Two types must match |
| Protocol composition | `T: Equatable & Hashable` | Multiple protocols |

```swift
// Protocol constraint
func areAllEqual<T: Equatable>(_ items: [T]) -> Bool {
    guard let first = items.first else { return true }
    for item in items.dropFirst() {
        guard item == first else { return false }
    }
    return true
}

print(areAllEqual([1, 1, 1]))  // true
print(areAllEqual([1, 2, 1]))  // false

// Where clause
func uniqueElements<T>(in array: [T]) -> [T] where T: Hashable {
    return Array(Set(array))
}
```

**Constrained Generic Types:**

```swift
struct Dictionary<Key: Hashable, Value> {
    // Key must be Hashable
}

// Where clause on type extension
extension Array where Element: Numeric {
    var sum: Element {
        reduce(0, +)
    }
}

print([1, 2, 3].sum)  // 6
// print(["a", "b"].sum)  // Error: String not Numeric
```

**Multiple Constraints:**

```swift
func compare<S1: Sequence, S2: Sequence>(_ s1: S1, _ s2: S2) -> Bool
    where S1.Element: Equatable,
          S1.Element == S2.Element {
    return zip(s1, s2).allSatisfy { $0 == $1 }
}
```

> **Key Point:** Use constraints to access type-specific functionality (like `==` for `Equatable`, or `hashValue` for `Hashable`). Without constraints, you can only use operations available to all types.

Constraints can be specified inline with `:` after the type parameter, or using a `where` clause for more complex requirements.

codeExample:
import Foundation

// Protocol constraint
func largest<T: Comparable>(in array: [T]) -> T? {
    array.max()
}

print(largest(in: [3, 7, 2, 9, 5]) ?? 0)
print(largest(in: ["apple", "banana", "cherry"]) ?? "")

// Where clause with multiple constraints
func sumNumericValues<T>(_ a: T, _ b: T) -> T where T: Numeric {
    a + b
}

print(sumNumericValues(10, 20))
print(sumNumericValues(3.5, 2.5))

// Class constraint
class Shape { }
class Circle: Shape { }

func describeShape<T: Shape>(_ shape: T) -> String {
    "This is a shape"
}

let circle = Circle()
print(describeShape(circle))

// Constrained extension
protocol JSONSerializable {
    func toJSON() -> String
}

extension Array where Element: JSONSerializable {
    func toJSONArray() -> String {
        let items = self.map { $0.toJSON() }
        return "[" + items.joined(separator: ",") + "]"
    }
}
